('computer-science:2-1-3-searching-and-sorting-algorithms:match:db2a69f2', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Linear search”?", "options": ["Checks each item in turn from the start until the target is found or the list ends", "One complete run through the list during a sort", "Removing the half of the list that cannot contain the target during a binary search", "Repeatedly compares adjacent items and swaps them if they are in the wrong order"]}'::jsonb, '{"answer": 0, "explain": "“Linear search” means: Checks each item in turn from the start until the target is found or the list ends"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:168eab1a', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Binary search”?", "options": ["Repeatedly checks the middle item of a sorted list and discards the half that cannot contain the target", "Exchanging the positions of two adjacent items that are in the wrong order", "Breaking a problem into smaller sub-problems, solving each, then combining the results", "Divides the list in half repeatedly, then merges the parts back together in order"]}'::jsonb, '{"answer": 0, "explain": "“Binary search” means: Repeatedly checks the middle item of a sorted list and discards the half that cannot contain the target"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:5448d963', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bubble sort”?", "options": ["Checks each item in turn from the start until the target is found or the list ends", "Divides the list in half repeatedly, then merges the parts back together in order", "Repeatedly compares adjacent items and swaps them if they are in the wrong order", "Arranging a list from smallest to largest"]}'::jsonb, '{"answer": 2, "explain": "“Bubble sort” means: Repeatedly compares adjacent items and swaps them if they are in the wrong order"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:324833e6', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Merge sort”?", "options": ["Divides the list in half repeatedly, then merges the parts back together in order", "The item a binary search checks first on each pass", "Repeatedly compares adjacent items and swaps them if they are in the wrong order", "Removing the half of the list that cannot contain the target during a binary search"]}'::jsonb, '{"answer": 0, "explain": "“Merge sort” means: Divides the list in half repeatedly, then merges the parts back together in order"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:2cb5d6e6', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Insertion sort”?", "options": ["Repeatedly checks the middle item of a sorted list and discards the half that cannot contain the target", "Arranging a list from smallest to largest", "Builds a sorted section one item at a time, inserting each new item into its correct place", "The item a binary search checks first on each pass"]}'::jsonb, '{"answer": 2, "explain": "“Insertion sort” means: Builds a sorted section one item at a time, inserting each new item into its correct place"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:9974bc10', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Pass”?", "options": ["Exchanging the positions of two adjacent items that are in the wrong order", "Removing the half of the list that cannot contain the target during a binary search", "One complete run through the list during a sort", "The item a binary search checks first on each pass"]}'::jsonb, '{"answer": 2, "explain": "“Pass” means: One complete run through the list during a sort"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:00da8c2e', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Swap”?", "options": ["Checks each item in turn from the start until the target is found or the list ends", "Exchanging the positions of two adjacent items that are in the wrong order", "Removing the half of the list that cannot contain the target during a binary search", "Builds a sorted section one item at a time, inserting each new item into its correct place"]}'::jsonb, '{"answer": 1, "explain": "“Swap” means: Exchanging the positions of two adjacent items that are in the wrong order"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:da5e821b', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Divide and conquer”?", "options": ["Breaking a problem into smaller sub-problems, solving each, then combining the results", "Repeatedly compares adjacent items and swaps them if they are in the wrong order", "Arranging a list from smallest to largest", "Divides the list in half repeatedly, then merges the parts back together in order"]}'::jsonb, '{"answer": 0, "explain": "“Divide and conquer” means: Breaking a problem into smaller sub-problems, solving each, then combining the results"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:3ff7ba7d', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sorted section”?", "options": ["Divides the list in half repeatedly, then merges the parts back together in order", "Builds a sorted section one item at a time, inserting each new item into its correct place", "The part of the list that insertion sort has already put into the correct order", "Arranging a list from smallest to largest"]}'::jsonb, '{"answer": 2, "explain": "“Sorted section” means: The part of the list that insertion sort has already put into the correct order"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:3c739781', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Middle item”?", "options": ["Breaking a problem into smaller sub-problems, solving each, then combining the results", "One complete run through the list during a sort", "The part of the list that insertion sort has already put into the correct order", "The item a binary search checks first on each pass"]}'::jsonb, '{"answer": 3, "explain": "“Middle item” means: The item a binary search checks first on each pass"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:ae55c915', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Discard”?", "options": ["One complete run through the list during a sort", "Removing the half of the list that cannot contain the target during a binary search", "Arranging a list from smallest to largest", "The item a binary search checks first on each pass"]}'::jsonb, '{"answer": 1, "explain": "“Discard” means: Removing the half of the list that cannot contain the target during a binary search"}'::jsonb),
('computer-science:2-1-3-searching-and-sorting-algorithms:match:9f8f45e5', 'computer-science', 'computer-science:2-1-3-searching-and-sorting-algorithms', '2.1.3 Searching and Sorting Algorithms', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ascending order”?", "options": ["The item a binary search checks first on each pass", "Repeatedly checks the middle item of a sorted list and discards the half that cannot contain the target", "Repeatedly compares adjacent items and swaps them if they are in the wrong order", "Arranging a list from smallest to largest"]}'::jsonb, '{"answer": 3, "explain": "“Ascending order” means: Arranging a list from smallest to largest"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:exam:92a90aac', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the programming construct that repeats a block of instructions.</p>", "options": ["Sequence", "Iteration", "Selection", "Assignment"], "hint": "Which word means ''repeating''?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Iteration</strong></li></ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul><li>Only the correct option scores; 2 or more ticks scores 0.</li></ul>\n</div>", "modelAnswer": "Iteration."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:exam:62bf5825', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to give the value of  <strong>19 MOD 4</strong>.</p>", "options": ["4", "3", "4.75", "16"], "hint": "MOD gives the remainder. How many are left over after taking 4s out of 19?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>3</strong> (4 goes into 19 four times = 16, leaving a remainder of 3)</li></ul>\n</div>", "modelAnswer": "3"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:5e1def3f', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "What is a constant?", "options": ["A named store in memory whose value the program is free to change as often as it needs to while running", "A named value that is set once and cannot change while the program runs", "An instruction that repeats a block of code a set number of times before the program finally moves on", "A symbol such as MOD or DIV that carries out a particular calculation on the numbers on either side of it"]}'::jsonb, '{"answer": 1, "explain": "A constant is a named value fixed for the run of the program. A store whose value can change is a variable."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:ed70e842', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "What is the result of  23 MOD 4 ?", "options": ["5 (which is how many whole times four divides into twenty-three, once the leftover remainder is ignored)", "3", "5.75", "4"]}'::jsonb, '{"answer": 1, "explain": "MOD gives the remainder: 4 goes into 23 five times (20), leaving 3. (23 DIV 4 would give 5.)"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:307dcf9b', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "Which operator gives the WHOLE number of times one value divides into another, ignoring any remainder?", "options": ["MOD", "DIV", "/", "^"]}'::jsonb, '{"answer": 1, "explain": "DIV is integer (whole-number) division. MOD gives the remainder, / gives a normal (possibly decimal) result, and ^ is exponent."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:ae07c629', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "Which of these is a comparison operator?", "options": ["The MOD operator, which is used to find the remainder that is left over after one whole-number division", "!=", "AND", "^"]}'::jsonb, '{"answer": 1, "explain": "!= (not equal to) is a comparison operator. MOD and ^ are arithmetic; AND is a Boolean operator."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:8053b2b7', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "A program contains the line  if x = 5 then  where the programmer meant to test whether x equals 5. What is wrong?", "options": ["Nothing is wrong; a single = sign is the correct and normal way to test whether two values are equal to each other", "= is assignment; to test for equality the condition should use == ", "The condition should use MOD instead of =, because MOD is the operator that checks whether two numbers match", "The word ''then'' is missing, and once it is added the single = sign will correctly compare the two values"]}'::jsonb, '{"answer": 1, "explain": "= assigns a value; comparing for equality needs ==. This is a very common error."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:46d389ed', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "The Boolean operator that is true only when BOTH of its conditions are true is:", "options": ["OR", "AND", "NOT", "MOD"]}'::jsonb, '{"answer": 1, "explain": "AND is true only if both sides are true. OR is true if either side is true, and NOT reverses a single condition."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:39cf7266', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "Which construct repeats a block of instructions?", "options": ["Sequence", "Iteration", "Selection", "Assignment"]}'::jsonb, '{"answer": 1, "explain": "Iteration means repetition (loops). Sequence runs in order, selection chooses a path, and assignment stores a value."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:ec960ae4', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "You need to repeat a block of code exactly 8 times. Which loop is most suitable?", "options": ["A condition-controlled while loop, because it will keep checking whether it has reached eight repetitions yet", "A count-controlled for loop", "No loop at all, because eight separate copies of the code should simply be written out one after another", "A selection statement, because the program has to decide each time whether it should repeat the code again"]}'::jsonb, '{"answer": 1, "explain": "The number of repetitions (8) is known in advance, so a count-controlled for loop is the natural choice."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:8de83fc1', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "What does  2 ^ 4  evaluate to?", "options": ["8, because the ^ operator simply multiplies the two numbers on either side of it together in the usual way", "16", "6", "24"]}'::jsonb, '{"answer": 1, "explain": "^ is ''to the power of'': 2 to the power 4 = 2×2×2×2 = 16."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:9fc05189', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "In a  do … until  loop, how many times does the body always run, at minimum?", "options": ["Zero, because the loop checks its condition before it runs the body even once, exactly like a while loop does", "At least once, because the condition is checked after the body has run", "Exactly the number stated by a counter that has to be set before the loop can begin running at all", "It can never be predicted, because a do…until loop runs its body a completely random number of times"]}'::jsonb, '{"answer": 1, "explain": "do…until checks the condition AFTER the body, so the body always runs at least once. A while loop can run zero times."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:95ff7d9b', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "Which line correctly assigns the number 0 to a variable called  total ?", "options": ["total == 0", "total = 0", "0 = total", "total := equals(0)"]}'::jsonb, '{"answer": 1, "explain": "Assignment stores the right-hand value into the left-hand name: total = 0. (== is comparison, and the value must go into the variable.)"}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:mcq:5e6b0e5d', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'mcq', 'mcq', 1, '{"question": "A condition is  age &lt; 13 OR age &gt; 65 . For which age is it TRUE?", "options": ["age = 40, because forty comfortably sits inside the normal range that the two conditions are describing together", "age = 70", "age = 30", "age = 13"]}'::jsonb, '{"answer": 1, "explain": "OR is true if either side is true. 70 is greater than 65, so the condition is true. 40, 30 and 13 satisfy neither side."}'::jsonb),
('computer-science:2-2-1-programming-fundamentals:tf:5e454f32', 'computer-science', 'computer-science:2-2-1-programming-fundamentals', '2.2.1 Programming Fundamentals', 'tf', 'tf', 1, '{"question": "The value stored in a variable can change while the program runs."}'::jsonb, '{"answer": true, "explain": "Correct — that is exactly what makes it a variable, as opposed to a constant which stays fixed."}'::jsonb)
